import {
  ApartmentOutlined,
} from '@ant-design/icons';
import {
  App,
  Button,
  Card,
  Drawer,
  Descriptions,
  Empty,
  Input,
  Spin,
  Table,
  Tabs,
  Tag,
  Typography,
  Progress,
} from 'antd';
import React, { useState, useCallback, useRef } from 'react';
import { GENERAL_CONFIG } from '../graphConfig';
import {
  discoverCommunities,
  getCommunityGraph,
  type Community,
  type DiscoverParams,
  type DiscoveryResult,
  type GraphData,
} from './service';
import { useCommunityGraph } from './hooks/useCommunityGraph';
import DiscoveryConfig from './components/DiscoveryConfig';
import CommunityDetail from './components/CommunityDetail';

const { Title, Text } = Typography;

const LAYER_COLORS: Record<string, string> = {
  Subject: '#1890ff',
  Event: '#ff4d4f',
  Feature: '#52c41a',
  Regulation: '#722ed1',
};

const CommunityDiscoveryPage: React.FC = () => {
  const { message } = App.useApp();

  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<DiscoveryResult | null>(null);
  const [selectedCommunity, setSelectedCommunity] = useState<Community | null>(null);
  const [graphData, setGraphData] = useState<GraphData>({ nodes: [], edges: [] });
  const [graphLoading, setGraphLoading] = useState(false);
  const [drawerVisible, setDrawerVisible] = useState(false);
  const [selectedNode, setSelectedNode] = useState<any>(null);
  const [searchText, setSearchText] = useState('');
  const [discoverParams, setDiscoverParams] = useState<DiscoverParams | null>(null);
  const [activeTab, setActiveTab] = useState('list');
  const [fullGraphData, setFullGraphData] = useState<GraphData>({ nodes: [], edges: [] });

  const graphContainerRef = useRef<HTMLDivElement>(null);
  const fullGraphContainerRef = useRef<HTMLDivElement>(null);

  const { downloadImage } = useCommunityGraph(graphContainerRef, {
    graphData,
    onNodeClick: (model) => {
      setSelectedNode(model);
      setDrawerVisible(true);
    },
  });

  useCommunityGraph(fullGraphContainerRef, {
    graphData: fullGraphData,
    onNodeClick: (model) => {
      // Find which community this node belongs to and select it
      if (result) {
        for (const c of result.communities) {
          const nodeIds = graphData.nodes.map((n: any) => String(n.id));
          if (nodeIds.includes(String(model.id))) {
            handleSelectCommunity(c);
            break;
          }
        }
      }
      setSelectedNode(model);
      setDrawerVisible(true);
    },
  });

  // ── Handlers ──

  const handleDiscover = useCallback(async (params: DiscoverParams) => {
    setDiscoverParams(params);
    setLoading(true);
    setSelectedCommunity(null);
    setGraphData({ nodes: [], edges: [] });
    setFullGraphData({ nodes: [], edges: [] });
    try {
      const data = await discoverCommunities(params);
      if (data.success) {
        setResult(data);
        message.success(`发现 ${data.communities_count} 个群体`);
      } else {
        message.error((data as any).error || '群体发现失败');
      }
    } catch {
      message.error('服务连接失败');
    } finally {
      setLoading(false);
    }
  }, []);

  const handleSelectCommunity = useCallback(
    async (community: Community) => {
      setSelectedCommunity(community);
      setGraphLoading(true);
      try {
        const layer = discoverParams?.layer || 'all';
        const data = await getCommunityGraph(community.community_id, layer);
        setGraphData({
          nodes: data.nodes || [],
          edges: data.edges || [],
        });
      } catch {
        message.error('加载子图失败');
      } finally {
        setGraphLoading(false);
      }
    },
    [discoverParams],
  );

  const handleReset = useCallback(() => {
    setResult(null);
    setSelectedCommunity(null);
    setGraphData({ nodes: [], edges: [] });
    setFullGraphData({ nodes: [], edges: [] });
    setDiscoverParams(null);
    setSearchText('');
  }, []);

  const handleViewFullGraph = useCallback(async () => {
    if (!result || !discoverParams) return;
    setActiveTab('graph');
    if (fullGraphData.nodes.length > 0) return;

    // Build merged graph data from all communities
    setGraphLoading(true);
    try {
      const layer = discoverParams.layer || 'all';
      const allNodes: any[] = [];
      const allEdges: any[] = [];
      const nodeSeen = new Set<string>();

      for (const c of result.communities.slice(0, 10)) {
        const data = await getCommunityGraph(c.community_id, layer, 100);
        for (const n of data.nodes || []) {
          const key = String(n.id);
          if (!nodeSeen.has(key)) {
            nodeSeen.add(key);
            (n as any)._communityId = c.community_id;
            allNodes.push(n);
          }
        }
        for (const e of data.edges || []) {
          allEdges.push(e);
        }
      }
      setFullGraphData({ nodes: allNodes, edges: allEdges });
    } catch {
      message.error('加载全图失败');
    } finally {
      setGraphLoading(false);
    }
  }, [result, discoverParams, fullGraphData.nodes.length]);

  const handleExportCSV = useCallback(() => {
    if (!selectedCommunity || graphData.nodes.length === 0) {
      message.warning('请先选择一个群体');
      return;
    }
    const nodeRows = graphData.nodes.map((n: any) => {
      const name = n.properties?.name || n.properties?.title || n.properties?.COMPANY_NM || '';
      const type = (n.labels || [])[0] || 'Unknown';
      return `${n.id},${name},${type}`;
    });
    const edgeRows = graphData.edges.map(
      (e: any) => `${e.source},${e.target},${e.label || ''}`,
    );
    const csv =
      'id,name,type\n' +
      nodeRows.join('\n') +
      '\n\nsource,target,label\n' +
      edgeRows.join('\n');
    const blob = new Blob(['﻿' + csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `community-${selectedCommunity.community_id}.csv`;
    link.click();
    URL.revokeObjectURL(url);
    message.success('CSV 导出成功');
  }, [selectedCommunity, graphData]);

  const handleExportPNG = useCallback(() => {
    if (graphData.nodes.length === 0) {
      message.warning('暂无图数据可导出');
      return;
    }
    downloadImage();
    message.success('PNG 导出已触发');
  }, [graphData.nodes.length, downloadImage]);

  // ── Filtered communities ──

  const filteredCommunities = result?.communities.filter((c) => {
    if (!searchText) return true;
    const text = searchText.toLowerCase();
    const topNames = c.top_entities?.map((e) => e.name.toLowerCase()).join(' ') || '';
    return (
      String(c.community_id + 1).includes(text) ||
      topNames.includes(text)
    );
  }) || [];

  // ── Community table columns ──

  const communityColumns = [
    {
      title: '#',
      dataIndex: 'community_id',
      width: 48,
      render: (_: any, __: Community, idx: number) => idx + 1,
    },
    {
      title: '规模',
      dataIndex: 'size',
      width: 64,
      sorter: (a: Community, b: Community) => a.size - b.size,
      render: (v: number) => <Text strong>{v}</Text>,
    },
    {
      title: '密度',
      dataIndex: 'density',
      width: 90,
      sorter: (a: Community, b: Community) => a.density - b.density,
      render: (v: number) => (
        <Progress
          percent={Math.round(v * 100)}
          size="small"
          format={() => v.toFixed(2)}
          strokeColor={v > 0.3 ? '#52c41a' : v > 0.1 ? '#faad14' : '#ff4d4f'}
        />
      ),
    },
    {
      title: '主要类型',
      dataIndex: 'label_distribution',
      width: 110,
      render: (dist: Record<string, number>) => {
        const sorted = Object.entries(dist || {}).sort((a, b) => b[1] - a[1]);
        if (!sorted.length) return <Tag>未知</Tag>;
        const [topLabel, count] = sorted[0];
        const total = sorted.reduce((s, [, c]) => s + c, 0);
        return (
          <Tag color={LAYER_COLORS[topLabel] || '#888'}>
            {topLabel} ({total > 0 ? Math.round((count / total) * 100) : 0}%)
          </Tag>
        );
      },
    },
    {
      title: '代表实体',
      dataIndex: 'top_entities',
      render: (entities: Array<{ name: string }>) =>
        entities?.slice(0, 3).map((e, i) => (
          <Tag key={i} style={{ marginBottom: 4 }}>
            {e.name}
          </Tag>
        )),
    },
  ];

  return (
    <div style={{ padding: '0 16px' }}>
      <Title level={4} style={{ marginBottom: 16 }}>
        <ApartmentOutlined style={{ marginRight: 8 }} />
        群体发现
      </Title>

      <div style={{ display: 'flex', flexDirection: 'column', gap: 12, height: 'calc(100vh - 160px)' }}>
        {/* ── Top: Config bar ── */}
        <DiscoveryConfig
          loading={loading}
          onDiscover={handleDiscover}
          onReset={handleReset}
          result={result}
        />

        {/* ── Bottom: Tabs (left) + Detail (right) ── */}
        <div style={{ display: 'flex', gap: 16, flex: 1, minHeight: 0 }}>
          {/* ── Left: Results (adaptive) ── */}
          <div style={{ flex: 1, minWidth: 0, display: 'flex', flexDirection: 'column' }}>
            {result ? (
              <Tabs
                activeKey={activeTab}
                onChange={setActiveTab}
                style={{ flex: 1, display: 'flex', flexDirection: 'column' }}
                tabBarExtraContent={
                  activeTab === 'list' ? (
                    <Input.Search
                      placeholder="搜索群体ID或实体名..."
                      allowClear
                      size="small"
                      style={{ width: 200 }}
                      value={searchText}
                      onChange={(e) => setSearchText(e.target.value)}
                    />
                  ) : null
                }
              >
                <Tabs.TabPane tab="群体列表" key="list">
                  <Table
                    dataSource={filteredCommunities}
                    columns={communityColumns}
                    rowKey="community_id"
                    size="small"
                    loading={loading}
                    pagination={{ pageSize: 15, size: 'small', showSizeChanger: false }}
                    scroll={{ y: 'calc(100vh - 310px)' }}
                    onRow={(record) => ({
                      onClick: () => handleSelectCommunity(record),
                      style: {
                        background:
                          selectedCommunity?.community_id === record.community_id
                            ? '#e6f7ff'
                            : undefined,
                        cursor: 'pointer',
                      },
                    })}
                  />
                </Tabs.TabPane>
                <Tabs.TabPane tab="图谱概览" key="graph">
                  {fullGraphData.nodes.length > 0 ? (
                    <div
                      ref={fullGraphContainerRef}
                      style={{ width: '100%', height: 'calc(100vh - 320px)', background: '#fafafa', borderRadius: 8 }}
                    />
                  ) : (
                    <Card size="small">
                      <Empty
                        description='点击「查看全图」加载群体概览图谱'
                        style={{ padding: 60 }}
                      >
                        <Button
                          type="primary"
                          loading={graphLoading}
                          onClick={handleViewFullGraph}
                        >
                          加载全图
                        </Button>
                      </Empty>
                    </Card>
                  )}
                </Tabs.TabPane>
              </Tabs>
            ) : (
              <Card size="small" style={{ flex: 1 }}>
                <Empty
                  description={
                    loading
                      ? '正在发现群体...'
                      : '选择算法后点击「开始发现」，然后在群体列表中选择一个群体查看详情'
                  }
                  style={{ padding: 80 }}
                >
                  {loading && <Spin size="large" />}
                </Empty>
              </Card>
            )}
          </div>

          {/* ── Right: Detail 360px ── */}
          <div style={{ width: 360, flexShrink: 0 }}>
            <CommunityDetail
              community={selectedCommunity}
              graphData={graphData}
              graphLoading={graphLoading}
              onClear={() => {
                setSelectedCommunity(null);
                setGraphData({ nodes: [], edges: [] });
              }}
              onNodeClick={(node) => {
                setSelectedNode(node);
                setDrawerVisible(true);
              }}
              onExportCSV={handleExportCSV}
              onExportPNG={handleExportPNG}
              onViewFullGraph={handleViewFullGraph}
            />
          </div>
        </div>
      </div>

      {/* ── Node detail drawer ── */}
      <Drawer
        title="节点详情"
        width={400}
        onClose={() => setDrawerVisible(false)}
        open={drawerVisible}
      >
        {selectedNode ? (
          <>
            <div style={{ textAlign: 'center', marginBottom: 16 }}>
              <div
                style={{
                  width: 56,
                  height: 56,
                  borderRadius: '50%',
                  backgroundColor: selectedNode.style?.fill || '#BFBFBF',
                  margin: '0 auto 8px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  color: '#fff',
                  fontSize: 22,
                  fontWeight: 'bold',
                }}
              >
                {selectedNode.fullLabel?.[0] || '?'}
              </div>
              <Title level={5} style={{ margin: 0 }}>
                {selectedNode.fullLabel || selectedNode.label}
              </Title>
              <Tag color={selectedNode.style?.fill}>{selectedNode.typeKey || 'Unknown'}</Tag>
            </div>
            <Descriptions column={1} bordered size="small">
              {Object.entries(selectedNode.properties || {}).map(([key, val]) => {
                if (val === null || val === undefined) return null;
                const label = GENERAL_CONFIG.propertyMap?.[key]?.label || key;
                return (
                  <Descriptions.Item label={label} key={key}>
                    {String(val).length > 100
                      ? String(val).substring(0, 100) + '...'
                      : String(val)}
                  </Descriptions.Item>
                );
              })}
            </Descriptions>
          </>
        ) : (
          <Empty />
        )}
      </Drawer>
    </div>
  );
};

export default CommunityDiscoveryPage;
